const body = $json.body || {};
const action = body.action || '';
const safeInput = JSON.stringify(body.input || {}).substring(0, 8000);
const safeOutput = JSON.stringify(body.output || {}).substring(0, 8000);
const safeTab = (body.tab || '').replace(/'/g, "''").substring(0, 100);
const safeType = (body.action_type || '').replace(/'/g, "''").substring(0, 100);
const safeTitle = (body.title || '').replace(/'/g, "''").substring(0, 500);
const safeLimit = parseInt(body.limit) || 20;
return [{ json: { ...$json, _route: action, _safeInput: safeInput, _safeOutput: safeOutput, _safeTab: safeTab, _safeType: safeType, _safeTitle: safeTitle, _safeLimit: safeLimit } }];
